const { ApolloServer, gql } = require('apollo-server');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');

const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    text: String!
    post: Post!
    user: User!
  }

  type Query {
    users: [User!]!
    user(id: ID!): User
    posts: [Post!]!
    post(id: ID!): Post
    comments: [Comment!]!
    comment(id: ID!): Comment
  }
`;

const users = [
  { id: '1', name: 'Alice', email: 'alice@example.com' },
  { id: '2', name: 'Bob', email: 'bob@example.com' },
  { id: '3', name: 'Charlie', email: 'charlie@example.com' },
];

const posts = [
  { id: '1', title: 'First Post', content: 'Hello World', authorId: '1' },
  { id: '2', title: 'Second Post', content: 'GraphQL is great', authorId: '2' },
  { id: '3', title: 'Third Post', content: 'Node.js rocks', authorId: '1' },
];

const comments = [
  { id: '1', text: 'Great post!', postId: '1', userId: '2' },
  { id: '2', text: 'Thanks for sharing', postId: '1', userId: '3' },
  { id: '3', text: 'Very informative', postId: '2', userId: '1' },
  { id: '4', text: 'I agree', postId: '2', userId: '3' },
  { id: '5', text: 'Nice work', postId: '3', userId: '2' },
];

const resolvers = {
  Query: {
    users: () => users,
    user: (_, { id }) => users.find(user => user.id === id),
    posts: () => posts,
    post: (_, { id }) => posts.find(post => post.id === id),
    comments: () => comments,
    comment: (_, { id }) => comments.find(comment => comment.id === id),
  },
  User: {
    posts: (user) => posts.filter(post => post.authorId === user.id),
  },
  Post: {
    author: (post) => users.find(user => user.id === post.authorId),
    comments: (post) => comments.filter(comment => comment.postId === post.id),
  },
  Comment: {
    post: (comment) => posts.find(post => post.id === comment.postId),
    user: (comment) => users.find(user => user.id === comment.userId),
  },
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [
    depthLimit(7),
    createComplexityLimitRule(1000, {
      onCost: (cost) => {
        console.log('Query cost:', cost);
      },
      formatErrorMessage: (cost) => 
        `Query is too complex: ${cost}. Maximum allowed complexity: 1000`,
      scalarCost: 1,
      objectCost: 2,
      listFactor: 10,
    }),
  ],
  introspection: process.env.NODE_ENV !== 'production',
  playground: process.env.NODE_ENV !== 'production',
  context: ({ req }) => {
    return {
      startTime: Date.now(),
    };
  },
  plugins: [
    {
      requestDidStart() {
        return {
          didEncounterErrors(requestContext) {
            console.error('GraphQL Errors:', requestContext.errors);
          },
          willSendResponse(requestContext) {
            const elapsed = Date.now() - requestContext.context.startTime;
            if (elapsed > 5000) {
              console.warn(`Slow query detected: ${elapsed}ms`);
            }
          },
        };
      },
    },
  ],
  formatError: (error) => {
    console.error('Error:', error);
    if (process.env.NODE_ENV === 'production') {
      return new Error('Internal server error');
    }
    return error;
  },
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});